    files: [
      { name: "calculator.html", lang: "html", content: "\u003c!DOCTYPE html\u003e\r\n\u003chtml lang=\"en\"\u003e\r\n\u003chead\u003e\r\n  \u003cmeta charset=\"UTF-8\"\u003e\r\n  \u003cmeta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\"\u003e\r\n  \u003clink rel=\"stylesheet\" href=\"calculator.css\"\u003e\r\n  \u003ctitle\u003eDocument\u003c/title\u003e\r\n\u003c/head\u003e\r\n\u003cbody\u003e\r\n  \u003cdiv id=\"calc\"\u003e\r\n    \u003cdiv id=\"dis\"\u003e\u003cinput id=\"screen\" readonly\u003e\u003c/div\u003e\r\n    \u003cdiv id=\"buttons\"\u003e\r\n      \u003cbutton type=\"button\" onclick=\"addToDisplay(\u00271\u0027)\"\u003e1\u003c/button\u003e\r\n      \u003cbutton type=\"button\" onclick=\"addToDisplay(\u00272\u0027)\"\u003e2\u003c/button\u003e\r\n      \u003cbutton type=\"button\" onclick=\"addToDisplay(\u00273\u0027)\"\u003e3\u003c/button\u003e\r\n      \u003cbutton type=\"button\" onclick=\"addToDisplay(\u0027-\u0027)\"\u003e-\u003c/button\u003e\r\n      \u003cbutton type=\"button\" onclick=\"addToDisplay(\u00274\u0027)\"\u003e4\u003c/button\u003e\r\n      \u003cbutton type=\"button\" onclick=\"addToDisplay(\u00275\u0027)\"\u003e5\u003c/button\u003e\r\n      \u003cbutton type=\"button\" onclick=\"addToDisplay(\u00276\u0027)\"\u003e6\u003c/button\u003e\r\n      \u003cbutton type=\"button\" onclick=\"addToDisplay(\u0027+\u0027)\"\u003e+\u003c/button\u003e\r\n      \u003cbutton type=\"button\" onclick=\"addToDisplay(\u00277\u0027)\"\u003e7\u003c/button\u003e\r\n      \u003cbutton type=\"button\" onclick=\"addToDisplay(\u00278\u0027)\"\u003e8\u003c/button\u003e\r\n      \u003cbutton type=\"button\" onclick=\"addToDisplay(\u00279\u0027)\"\u003e9\u003c/button\u003e\r\n      \u003cbutton type=\"button\" onclick=\"addToDisplay(\u0027*\u0027)\"\u003e*\u003c/button\u003e\r\n      \u003cbutton type=\"button\" onclick=\"addToDisplay(\u0027C\u0027)\"\u003eC\u003c/button\u003e\r\n      \u003cbutton type=\"button\" onclick=\"addToDisplay(\u00270\u0027)\"\u003e0\u003c/button\u003e\r\n      \u003cbutton type=\"button\" onclick=\"addToDisplay(\u0027.\u0027)\"\u003e.\u003c/button\u003e\r\n      \u003cbutton type=\"button\" onclick=\"compute()\"\u003e=\u003c/button\u003e\r\n    \u003c/div\u003e\r\n  \u003c/div\u003e\r\n\r\n  \u003cscript src=\"calculator.js\"\u003e\u003c/script\u003e\r\n\u003c/body\u003e\r\n\u003c/html\u003e" },
      { name: "calculator.js", lang: "javascript", content: "function addToDisplay(value) {\r\n  const screen = document.getElementById(\u0027screen\u0027);\r\n  if (value === \u0027C\u0027) return screen.value = \u0027\u0027;\r\n  const ops = \u0027+-*/\u0027;\r\n  const last = screen.value.slice(-1);\r\n  if (ops.includes(value) \u0026\u0026 (!screen.value || ops.includes(last))) return;\r\n  screen.value += value;\r\n}\r\n\r\nfunction compute() {\r\n  const screen = document.getElementById(\u0027screen\u0027);\r\n  if (!screen.value) return;\r\n  try {\r\n    screen.value = String(eval(screen.value));\r\n  } catch {\r\n    screen.value = \u0027Error\u0027;\r\n    setTimeout(() =\u003e screen.value = \u0027\u0027, 1200);\r\n  }\r\n}\r\n" },
      { name: "calculator.css", lang: "css", content: "body {\r\n  display: flex;\r\n  justify-content: center;\r\n  align-items: center;\r\n  min-height: 100vh;\r\n  margin: 0;\r\n  background: radial-gradient(circle at top, #5c6aff 0%, #1a2348 60%, #10172d 100%);\r\n  font-family: \u0027Inter\u0027, Arial, sans-serif;\r\n  color: #111;\r\n}\r\n\r\n#calc {\r\n  width: 310px;\r\n  padding: 22px;\r\n  border-radius: 28px;\r\n  background: linear-gradient(180deg, #f8faff 0%, #e8f2ff 100%);\r\n  box-shadow: 0 24px 60px rgba(0, 0, 0, 0.25);\r\n  border: 1px solid rgba(255,255,255,0.8);\r\n}\r\n\r\n#dis {\r\n  background: #131822;\r\n  color: #eef5ff;\r\n  text-align: right;\r\n  padding: 18px 16px;\r\n  margin-bottom: 20px;\r\n  border-radius: 20px;\r\n  box-shadow: inset 0 4px 10px rgba(0,0,0,0.25);\r\n  font-size: 32px;\r\n  letter-spacing: 0.03em;\r\n}\r\n\r\n#screen {\r\n  width: 100%;\r\n  border: none;\r\n  background: transparent;\r\n  color: inherit;\r\n  font-size: inherit;\r\n  text-align: right;\r\n  outline: none;\r\n}\r\n\r\n#buttons {\r\n  display: grid;\r\n  grid-template-columns: repeat(4, minmax(0, 1fr));\r\n  gap: 10px;\r\n}\r\n\r\nbutton {\r\n  padding: 18px 0;\r\n  font-size: 18px;\r\n  border: none;\r\n  border-radius: 16px;\r\n  background: #f4f5ff;\r\n  color: #1f2640;\r\n  box-shadow: 0 10px 18px rgba(24, 38, 82, 0.12);\r\n  cursor: pointer;\r\n  transition: transform 0.15s ease, background 0.15s ease, box-shadow 0.15s ease;\r\n}\r\n\r\nbutton:hover {\r\n  background: #e9ecff;\r\n  transform: translateY(-1px);\r\n}\r\n\r\nbutton:active {\r\n  transform: translateY(1px);\r\n  box-shadow: 0 6px 12px rgba(24, 38, 82, 0.18);\r\n}\r\n\r\n#buttons button:nth-child(4n) {\r\n  background: #5c6aff;\r\n  color: #fff;\r\n  box-shadow: 0 10px 20px rgba(92, 106, 255, 0.35);\r\n}\r\n\r\n#buttons button:nth-child(4n):hover {\r\n  background: #4657e1;\r\n}\r\n\r\n#buttons button:nth-child(4n):active {\r\n  background: #3a47c0;\r\n}" }
    ]
